function App() {
  return (
    <div>
      <h1>Smart EMI Calculator</h1>

      <input type="number" placeholder="Loan Amount" />
      <br />

      <input type="number" placeholder="Interest Rate (%)" />
      <br />

      <input type="number" placeholder="Time (Years)" />
      <br />

      <button>Calculate EMI</button>
    </div>
  );
}

export default App;
